const raw = $input.first().json;

// Parse vision API response
const content = raw?.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  parsed = {
    image_type: 'other',
    summary: 'Could not parse image content',
    extracted_order_number: null,
    extracted_tracking_number: null,
    extracted_amount: null
  };
}

// These image types go straight to escalation - no AI Agent
const escalateTypes = ['damaged_package', 'wrong_item', 'other'];
const needsEscalation = escalateTypes.includes(parsed.image_type);

// Build enriched text message for AI Agent
// Agent reads this as normal text and uses its tools on it
const enrichedParts = [
  `Customer message: ${$('Parse & Normalize.1.2').item.json.message_text || 'No text message'}`,
  `Image type: ${parsed.image_type}`,
  parsed.extracted_order_number ? `Order number from image: ${parsed.extracted_order_number}` : null,
  parsed.extracted_tracking_number ? `Tracking number from image: ${parsed.extracted_tracking_number}` : null,
  parsed.extracted_amount ? `Amount from image: ${parsed.extracted_amount}` : null,
  `Image summary: ${parsed.summary}`
].filter(Boolean).join('\n');

// Build escalation message for damaged/wrong item cases
const customerName = $('Parse & Normalize.1.2').item.json.raw_payload.source.author.name || '';
const language = $('Parse & Normalize.1.2').item.json.raw_payload.custom_attributes?.Language || 'English';

let escalationOutput;
if (language.toLowerCase().includes('fr')) {
  escalationOutput = `Je suis vraiment désolé de voir ça${customerName ? ', ' + customerName.split(' ')[0] : ''}. Laissez-moi vous connecter avec notre équipe qui pourra résoudre ce problème immédiatement.\n\nESCALATE\n\nIls seront avec vous sous peu! 😊`;
} else {
  escalationOutput = `I'm so sorry to see this${customerName ? ', ' + customerName.split(' ')[0] : ''}. Let me connect you with our team who can resolve this right away.\n\nESCALATE\n\nThey'll be with you shortly! 😊`;
}

return [{
  json: {
  Image_data:{
    ...parsed,
    needs_escalation: needsEscalation,
    enriched_message: enrichedParts,
  }  
  }
}];

const raw = $input.first().json;

const body = raw.body || {};
const item = body.data?.item || {};
const source = item.source || {};
const contact = item.contacts?.contacts?.[0] || {};
const firstPart = item.conversation_parts?.conversation_parts?.[0] || {};

const author = source.author || firstPart.author || {};

const conversationId = item.id || '';
const userId = contact.id || author.id || '';
const userEmail = author.email || null;

const brand = item.custom_attributes?.Brand || null;
const topic = body.topic || '';

const authorType = author.type || 'user';
const authorId = author.id || '';

const rawMessage =
  source.body ||
  firstPart.body ||
  '';

function stripHtml(html = '') {
  return html.replace(/<[^>]*>/g, '').trim();
}

const messageText = stripHtml(rawMessage);

const isAIReply =
  author.from_ai_agent === true ||
  author.is_ai_answer === true;

const hasAttachments =
  (source.attachments?.length || 0) > 0 ||
  (firstPart.attachments?.length || 0) > 0;

const tagNames =
  item.tags?.tags?.map(tag => tag.name) || [];

const eventId = body.id || '';

const channel = source.delivered_as || 'intercom';

// Custom logic flags
const isEtransfer =
  /e-?transfer|bank transfer|wire transfer/i.test(messageText);

const isHumanHandling =
  item.admin_assignee_id !== null ||
  item.team_assignee_id !== null;

const blockedEmails = [
  'no-reply@example.com',
  'test@example.com'
];

const allowedBrands = [
  'NS4L'
];

const isBlockedSenderEmail =
  blockedEmails.includes((userEmail || '').toLowerCase());

const isWrongBrand =
  brand ? !allowedBrands.includes(brand) : false;

const shouldSkip =
  isAIReply ||
  isBlockedSenderEmail ||
  isWrongBrand;

return [{
  json: {
    conversation_id: String(conversationId),
    user_id: String(userId || 'unknown'),
    user_email: userEmail || null,
    brand: brand || null,
    topic: topic || '',
    author_type: authorType || 'user',
    author_id: String(authorId || ''),
    message_text: messageText.substring(0, 500),
    is_ai_reply: !!isAIReply,
    is_etransfer: !!isEtransfer,
    has_attachments: !!hasAttachments,
    should_skip: !!shouldSkip,
    isBlockedSenderEmail: !!isBlockedSenderEmail,
    isWrongBrand: !!isWrongBrand,

    // Debugging
    event_id: eventId,
    channel: channel,
    timestamp: new Date().toISOString(),
    raw_subject: source.subject || '',
    tags: tagNames,

    // Original normalized payload
    raw_payload: item
  }
}];

